// // This module calculates the parity of four one-bit inputs using AND gates instead of XOR gates.
module top_module(
    input A,
    input B,
    input C,
    input D,
    output parity
);wire ab, cd, abcd;

    xor(ab, A, B);
    xor(cd, C, D);
    xor(abcd, ab, cd);
    assign parity = abcd;

endmodule
